import{c as t,Q as e,j as r,m as a}from"./chunks/framework.rlpw0eGz.js";const p=JSON.parse('{"title":"飞书（Lark）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/channels/feishu.md","filePath":"zh/channels/feishu.md","lastUpdated":1777012567000}'),n={name:"zh/channels/feishu.md"};function s(l,o,i,h,g,c){return e(),r("div",null,[...o[0]||(o[0]=[a('<h1 id="飞书-lark" tabindex="-1">飞书（Lark） <a class="header-anchor" href="#飞书-lark" aria-label="Permalink to &quot;飞书（Lark）&quot;">​</a></h1><p>通过飞书开放平台接企业内机器人在群/私聊里用。</p><h2 id="_1-建飞书应用" tabindex="-1">1. 建飞书应用 <a class="header-anchor" href="#_1-建飞书应用" aria-label="Permalink to &quot;1. 建飞书应用&quot;">​</a></h2><ol><li>打开 <a href="https://open.feishu.cn/app" target="_blank" rel="noreferrer">飞书开放平台</a> 并登录。</li><li><strong>创建企业自建应用</strong>，填名与简介。</li><li>左侧 <strong>应用能力</strong> 或 <strong>凭证与基础信息</strong> 里取 <strong>App ID</strong>、<strong>App Secret</strong>。</li></ol><h2 id="_2-开机器人能力" tabindex="-1">2. 开机器人能力 <a class="header-anchor" href="#_2-开机器人能力" aria-label="Permalink to &quot;2. 开机器人能力&quot;">​</a></h2><p>控制台 <strong>应用能力</strong> → <strong>机器人</strong> → 启用。</p><h2 id="_3-开权限" tabindex="-1">3. 开权限 <a class="header-anchor" href="#_3-开权限" aria-label="Permalink to &quot;3. 开权限&quot;">​</a></h2><p><strong>应用能力</strong> → <strong>权限管理</strong>，至少可开（按组织要求可能需审批）：</p><ul><li><code>im:message</code>（收发信息）</li><li><code>im:chat</code>（群信息等）</li></ul><p>需时点 <strong>申请权限</strong>。</p><h2 id="_4-事件-webhook-入站" tabindex="-1">4. 事件：Webhook 入站 <a class="header-anchor" href="#_4-事件-webhook-入站" aria-label="Permalink to &quot;4. 事件：Webhook 入站&quot;">​</a></h2><ol><li>Memoh 里该机器人 <strong>Platforms</strong> → 加 <strong>飞书</strong>，<strong>入站方式</strong> 选 <code>webhook</code>。</li><li>填 <strong>App ID</strong>、<strong>App Secret</strong>。</li><li><strong>Save</strong>，页面上会出现 <strong>Webhook 回调 URL</strong>，复制。</li><li>飞书后台 <strong>应用配置</strong> → <strong>事件订阅</strong>。</li><li>把上面 URL 填到 <strong>请求地址</strong> 等对应栏位并保存。</li><li>订阅如 <strong>接收消息</strong>（<code>im.message.receive_v1</code> 等，以当前控制台为准）。</li></ol><blockquote><p>官方： <a href="https://open.feishu.cn/document/client-docs/bot-v3/add-custom-bot" target="_blank" rel="noreferrer">飞书自定义机器人</a></p></blockquote><h2 id="_5-发布" tabindex="-1">5. 发布 <a class="header-anchor" href="#_5-发布" aria-label="Permalink to &quot;5. 发布&quot;">​</a></h2><p><strong>应用发布</strong> → <strong>版本管理与发布</strong>，建版本、走审批/发布。通过后机器人才能在租户里正常用。</p>',15)])])}const _=t(n,[["render",s]]);export{p as __pageData,_ as default};
